function skz(x: number, y: number): string {
  let k: string = ""
  for (let l: number = 0; l < x; l++) {
    for (let p: number = 0; p < y; p++) {
      if ((p + l) % 3 == 0) {
        k = k + "K"
      } else if ((p + l) % 3 == 1) {
        k = k + "L"
      } else {
        k = k + "P"
      }
      k = k + " "
    }
    k = k + "\n" // quebra a linha
  }
  return k
}
